const path = require('path');
const { expect } = require('chai');
const winston = require('winston');
const Bootstrap = require('../../../src/core/Bootstrap');
const StageExecutor = require('../../../src/core/StageExecutor');
const { STAGES } = require('../../../src/core/StageRegistry');
const DiContainer = require('../../../src/core/DiContainer'); // Singleton
const AnnotationRegistry = require('../../../src/core/AnnotationRegistry');
const AnnotationParser = require('../../../src/core/AstAnnotationParser');

// Winston-Logger für Tests
const logger = winston.createLogger({
  level: 'debug',
  format: winston.format.printf(({ level, message }) => {
    const now = new Date();
    const timestamp = now.toTimeString().split(' ')[0]; // HH:mm:ss
    return `${timestamp}-${level.toUpperCase()}-${message}`;
  }),
  transports: [new winston.transports.Console()]
});

describe('Functional: Bootstrap stage flow', () => {
  it('should execute all configured stages in correct order', async () => {
    const contextLog = [];

    STAGES.forEach(stage => {
      StageExecutor.registerStageProcessor(
        stage,
        context => context.log.push(`Stage: ${stage}`)
      );
    });

    const options = {
      baseDir: __dirname,
      scanDirs: [],
      container: DiContainer,
      metadata: {},
      log: contextLog
    };

    await Bootstrap.run(options);

    expect(contextLog).to.deep.equal(STAGES.map(stage => `Stage: ${stage}`));
  });
});

describe('Bootstrap (Functional)', () => {
  beforeEach(() => {
    // Singleton-Container vor jedem Test zurücksetzen
    DiContainer.reset();
  });

  describe('Functional Test: Simple Mock Project', () => {
    it('should load components and register resources', async () => {
      const log = [];

      const mockProjectRoot = path.join(__dirname, '../../mocks/projects/simple');
      const componentsDir = path.join(mockProjectRoot, 'components');
      const servicesDir = path.join(mockProjectRoot, 'service');

      await Bootstrap.run({
        baseDir: mockProjectRoot,
        scanDirs: [componentsDir, servicesDir],
        container: DiContainer,
        log
      });

      expect(DiContainer.has('fs')).to.be.true;
      expect(DiContainer.has('UserService')).to.be.true;
      expect(DiContainer.has('AppComponent')).to.be.true;

      expect(log).to.include('@Require registered: fs → fs');
      expect(log).to.include('@Require registered: UserService → ./service/SimpleUserService');
      expect(log).to.include('@Component instantiated: AppComponent');
      expect(log).to.include('@Component instantiated: UserService');

      // Debug-Logs mit Winston
      log.forEach(line => logger.debug(line));
    });
  });

  describe('Functional Test: Complex Mock Project', () => {
    it('should load all components, requires and inject qualifiers', async () => {
      const log = [];

      const mockProjectRoot = path.join(__dirname, '../../mocks/projects/complex');
      const componentsDir = path.join(mockProjectRoot, 'components');
      const servicesDir = path.join(mockProjectRoot, 'service');
      const resourcesDir = path.join(mockProjectRoot, 'resources');

      await Bootstrap.run({
        baseDir: mockProjectRoot,
        scanDirs: [componentsDir, servicesDir, resourcesDir],
        container: DiContainer,
        log
      });

      logger.debug('--- COMPLEX FUNCTIONAL DEBUG LOG ---');
      log.forEach(line => logger.debug(line));
      logger.debug('--- END DEBUG LOG ---');

      const app = DiContainer.resolve('AppComponent');
      const userComponent = DiContainer.resolve('UserComponent');
      const userService = DiContainer.resolve('UserService');
      const dbService = DiContainer.resolve('Database');

      // Debug-Logs der Objekte
      logger.debug(`DEBUG: app.userComponent: ${JSON.stringify(app.userComponent)}`);
      logger.debug(`DEBUG: userComponent.userService: ${JSON.stringify(userComponent.userService)}`);
      logger.debug(`DEBUG: userService.db: ${JSON.stringify(userService.db)}`);
      logger.debug(`DEBUG: app.userComponent.userService.db: ${JSON.stringify(app.userComponent?.userService?.db)}`);

      expect(app).to.exist;
      expect(userComponent).to.exist;
      expect(userService).to.exist;
      expect(dbService).to.exist;

      // Prüfen, ob Qualifier-Injektionen korrekt durchgeführt wurden
      expect(app.userComponent).to.equal(userComponent);
      expect(userComponent.userService).to.equal(userService);
      expect(userService.db).to.equal(dbService);

      // Optional: Lifecycle-Logs prüfen
      expect(log).to.include('@Component instantiated: Database');
      expect(log).to.include('@Component instantiated: UserService');
      expect(log).to.include('@Component instantiated: UserComponent');
      expect(log).to.include('@Component instantiated: AppComponent');
    });
  });
});
